INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-07190', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '對於臺灣日治時期社區工作的發展歷史，下列何者錯誤？', '["類似西方睦鄰運動，以稻垣藤兵衛於1916年在臺北大稻埕所設立「人類之家」最早", "「鄰保館」是因1936年東勢地區大地震，為了災後重建並增進當地居民之福利與教化而設立", "臺灣第一個「鄰保館」事業係由財團法人嘉義博愛會於臺南州嘉義市設置", "「方面委員會」是仿效德國愛爾伯福制度（Elberfeld System）設立"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07191', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列情境中，社會工作者運用的是何種會談技巧？ 案主是個成年女性，她的問題是丈夫不喜歡和她相處。案主的先生曾經抱怨：「我每次和她說話，她就 不知道飄忽到那裡去，也許是到了白日夢的世界」。社會工作者在與案主會談中，則是發現她的注意力 常常迷失，就和她丈夫陳述的一樣。在這次會談中，社會工作者和案主說：「就在我們說話的時刻，我 注意到妳的眼神根本沒有注視我，妳好像在看著遠方而在想些什麼事情似的，妳現在到底在想些什麼？」', '["重新建構（reframing）", "面質（confronting）", "立即性反應（responding with immediacy）", "同理（empathy）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07192', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區工作者做過了社區需求調查之後，依據自己的專業，研擬了一套具體的方案，進入社區並加以執行， 這是何種社區工作模式？', '["地區發展模式", "社會計畫模式", "社會行動模式", "社區建設模式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07193', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「依據社會正義或民主的理念，將社區中處於劣勢地位者，組織起來，而後對社會提出適當的要求，如 資源的增加或合理的對待」。上述概念指的是學者Rothman與Tropman（1987）提出的「社區工作三模 式」中的那一個模式？', '["社會行動模式", "社會計畫模式", "社會干預模式", "社區發展模式"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07194', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「當一個新住民家庭不瞭解符合他們特殊需求的各種服務時，社會工作者告知家庭有那些可用的服務並 協助使用這些服務，增加其使用服務的相關知能，以順利達成任務，並能產生後續面對與處理困境的信 心」。上述這些工作內涵，是家庭社會工作者的何種角色？', '["動員者", "倡導者", "協調者", "使能者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07195', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「身為社會福利機構的一員，社會工作者有責任評估組織結構、機構政策與阻礙有效服務輸送的機構內 部功能關係，這些相關的角色包括團隊成員、督導者、組織分析者等」，上述是直接服務社會工作者多 重角色中的那一類型角色？', '["研究者和研究使用者", "系統的維護與增強者", "系統的發展者", "系統的連結者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07196', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '對於兒童的疏忽或虐待，社工員經過家庭評估之後，決定先暫時將兒童安置於適當的場所，俟原生家庭 功能恢復，再協助兒童返家，此一處置方案稱為：', '["家庭維繫方案", "家庭重整方案", "家庭個管方案", "家庭替代方案"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07197', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「在社區工作中，我們不能簡單的依據經驗和客觀事實來定義社區問題，而必須嵌入有意義的網絡中， 不僅是透過個別化的處置方案為其提供諮詢服務，還必須進行背景闡釋。」這段話是何種理論的觀點？', '["社會學習理論", "組織相互關係理論", "結構功能理論", "現實建構理論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07198', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體領導者通常需與來自不同背景或文化的人一起工作，若領導者具有文化敏感度，則較能為和自己不 同背景的成員提供適切服務，下列關於領導者面對不同文化背景成員實務運作原則的敘述，何者錯誤？', '["領導者應該協助少數民族的團體成員瞭解，由於其缺少相關的知識與訊息，他們的經驗與看法對團體 任務的達成缺少助益，是合理的", "領導者需協助成員瞭解其在過去生活中所經歷的歧視，及這些經驗對目前問題與困境的影響，以透過 瞭解，逐步增加其正向的自我認同", "領導者應協助成員在團體中，瞭解彼此相同與不同的文化價值觀與生活經驗，藉由各類經驗的交流分 享，增進團體成員的相互尊重與互動", "對於少數民族的團體成員遭遇服務體系不當對待時，在團體之外進行倡導的工作，是領導者的重要任 務之一"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07199', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列有關團體評估（evaluation）的敘述，何者錯誤？', '["團體成效的測量可分為自陳式測量與觀察式測量，前者由成員提供資料，後者則是由工作者觀察", "可分為過程評估與結果評估，前者可瞭解團體總目標的達成情況和團體最後的成效", "考量服務的責信，工作者需對團體的過程、成效等面向，運用合適的方式進行評估", "評估是動態的過程，在團體的每個階段（開始、中間、結束）都應該進行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
